css:
.ps-wiki-dialog { border: 1px solid var(--pds-border-subtle); border-radius: var(--pds-radius-md); padding: 0; background: var(--pds-surface-layer); color: var(--pds-text-primary); max-width: min(90vw, 40rem); width: 100%; }
.ps-wiki-dialog::backdrop { background: rgba(0,0,0,0.5); }
.ps-wiki-dialog[open] { animation: dialog-in var(--pds-duration-base) var(--pds-easing-decelerate) both; }
@keyframes dialog-in { from { opacity: 0; transform: translateY(-0.5rem); } to { opacity: 1; transform: none; } }
.ps-wiki-dialog__content { display: flex; flex-direction: column; }
.ps-wiki-dialog__header { display: flex; align-items: center; justify-content: space-between; padding: var(--pds-space-2) var(--pds-space-4); border-block-end: 1px solid var(--pds-border-subtle); }
.ps-wiki-dialog__title { font-size: 1.125rem; font-weight: 600; margin: 0; }
.ps-wiki-dialog__close { background: transparent; border: none; cursor: pointer; font-size: 1.25rem; color: var(--pds-text-secondary); padding: var(--pds-space-05); }
.ps-wiki-dialog__body { padding: var(--pds-space-4); overflow-y: auto; }
.ps-wiki-dialog__footer { padding: var(--pds-space-2) var(--pds-space-4); border-block-start: 1px solid var(--pds-border-subtle); display: flex; justify-content: flex-end; gap: var(--pds-space-1); }
